// 2. KONDISI CADANGAN JIKA STRUKTUR PAYLOAD KOSONG/TIDAK BERISI JAWABAN
if (!msg.payload || !msg.payload.candidates) {
    const errText = "❌ **Error:** Gagal mendapatkan respons data dari AI. Silakan coba beberapa saat lagi!";
    msg.res = msg.res || msg._expressRes;
    msg.payload = { jawaban: errText, content: errText };
    msg.channelId = msg.chat_id;
    msg.channel = msg.chat_id;
    return msg;
}

// 3. JALUR SUKSES: JIKA GEMINI BERHASIL MEMBERIKAN JAWABAN RAG
let jawaban_ai = msg.payload.candidates[0].content.parts[0].text;
jawaban_ai = jawaban_ai.replace(/\r\n/g, "\n").replace(/\n{3,}/g, "\n\n").replace(/^\s*\.{2,}\s*$/gm, "").trim();

// JALUR PENYELAMAT: Cek jika teks melebihi limit Discord (2000 karakter)
if (jawaban_ai.length > 2000) {
    // Potong di 1950 karakter, lalu sambung dengan pesan peringatan
    jawaban_ai = jawaban_ai.substring(0, 1950) + "\n\n...(Teks terpotong karena batas maksimal 2000 karakter Discord)...";
}

msg.res = msg.res || msg._expressRes;
msg.payload = { jawaban: jawaban_ai, content: jawaban_ai };
msg.channelId = msg.chat_id;
msg.channel = msg.chat_id;
return msg;

msg.pertanyaan = msg.pertanyaan.replace(/^\/delfilm\s*/i, "").trim();
if (!msg.pertanyaan) {
    msg.payload = { "chatId": msg.chat_id, "type": "message", "content": "Format salah! Contoh: !hapusfilm CENTER DINOSAUR" };
    return [null, msg];
}

let contextPrompt = "TUGAS: Buat query SQL MySQL DELETE murni untuk tabel 'film_denorm' berdasarkan permintaan user.\n" +
                    "STRUKTUR TABEL 'film_denorm': film_id, title, description, category, price, length, rating, actors.\n\n" +
                    "ATURAN:\n" +
                    "- Cari tahu judul film atau film_id yang ingin dihapus untuk dimasukkan ke klausa WHERE.\n" +
                    "- JAWAB HANYA STRING SQL MURNI TANPA BACKTICK DAN TANPA TITIK KOMA (;) DI AKHIR.\n\n" +
                    "Permintaan User: " + msg.pertanyaan;

msg.payload = {
    "contents": [{
        "parts": [{"text": contextPrompt}]
    }]
};

return [msg, null];

if (!msg.payload.candidates) {
    msg.payload = { "chatId": msg.chat_id, "type": "message", "content": "Gagal membuat SQL (Rate Limit). Coba beberapa saat lagi." };
    return [null, msg];
}
let rawText = msg.payload.candidates[0].content.parts[0].text;
msg.topic = rawText.replace(/`{3}sql|`{3}/g, "").trim();
msg.payload = msg.topic;
return [msg, null];

let status_db = JSON.stringify(msg.payload);
let pertanyaan_user = msg.pertanyaan || "";
let id_chat = msg.chat_id;

// RESET TOTAL OBJEK MSG UNTUK MENGHINDARI JSON PARSE ERROR
let cleanMsg = {
    pertanyaan: pertanyaan_user,
    chat_id: id_chat,
    res: msg.res || msg._expressRes,
    _expressRes: msg._expressRes || msg.res,
    req: msg.req || msg._httpReq,
    headers: {
        "Content-Type": "application/json"
    },
    payload: JSON.stringify({
        "contents": [{
            "parts": [{
                "text": "Kamu adalah asisten film CineChat. Berikan konfirmasi singkat (1-2 kalimat) bahwa aksi hapus film (Delete) berhasil.\n\nATURAN: langsung ke inti, tanpa basa-basi atau emoji berlebihan. Gunakan **tebal** untuk judul film jika disebutkan. Bahasa Indonesia sopan.\n\nLog Status MySQL:\n" + status_db
            }],
        }]
    })
};

return cleanMsg;

if (msg.payload && typeof msg.payload === "string") {
    msg.pertanyaan = msg.payload; 
    msg.chat_id = msg.chat_id || "web-session";
}
return msg;

if (msg.payload && msg.payload.pertanyaan) {
    let userMode = msg.payload.mode || "rag";
    let teksUser = msg.payload.pertanyaan.trim();
    const sessionId = msg.payload.sessionId || msg.chat_id || "web-session";

    // Otomatis bungkus ke format command agar lolos filter Regex Router
    if (userMode === "rag") {
        msg.payload = "/rag " + teksUser;
    } else if (userMode === "oltp") {
        msg.payload = "/sqln " + teksUser;
    } else if (userMode === "dwh") {
        msg.payload = "/sqld " + teksUser;
    } else if (userMode === "addfilm") {
        msg.payload = "/addfilm " + teksUser;
    } else if (userMode === "editfilm") {
        msg.payload = "/editfilm " + teksUser;
    } else if (userMode === "delfilm") {
        msg.payload = "/delfilm " + teksUser;
    } else {
        msg.payload = teksUser;
    }

    msg.chat_id = sessionId;
    msg._expressRes = msg.res;
    msg._httpReq = msg.req;
}
return msg;
